var data = (typeof msg.payload === "string") ? JSON.parse(msg.payload) : (msg.payload || {});
var raw = data.raw || data;
var rssiVal = (data.rssi !== undefined) ? data.rssi : raw.rssi;
var snrVal = (data.snr !== undefined) ? data.snr : raw.snr;

var fields = {
    latitude: parseFloat(raw.lat) || 0.0,
    longitude: parseFloat(raw.lon) || 0.0,
    rssi: parseInt(rssiVal) || 0,
    snr: parseFloat(snrVal) || 0.0,
    battery: parseFloat(raw.battery) || 100.0,
    wake_count: parseInt(raw.wake_count) || 0
};
var tags = {
    device_id: raw.device_id || "edge-01",
    fence_status: raw.fence_status || "UNKNOWN"
};
msg.payload = [fields, tags];
return msg;

var rows = msg.payload;
if (!rows || !Array.isArray(rows) || rows.length === 0) {
    return null;
}

// Obtener coordenadas de la geocerca (bounding box y vértices si existen)
var fenceMinLat = flow.get('fence_min_lat') || global.get('fence_min_lat') || -34.9250;
var fenceMaxLat = flow.get('fence_max_lat') || global.get('fence_max_lat') || -34.9150;
var fenceMinLon = flow.get('fence_min_lon') || global.get('fence_min_lon') || -57.9600;
var fenceMaxLon = flow.get('fence_max_lon') || global.get('fence_max_lon') || -57.9450;
var vJson = flow.get('fence_vertices_json') || global.get('fence_vertices_json');
var vertices = null;
if (vJson) {
    try { vertices = JSON.parse(vJson); } catch(e) {}
}

var centerLat = (fenceMinLat + fenceMaxLat) / 2;
var centerLon = (fenceMinLon + fenceMaxLon) / 2;
var R = 6378137.0;
var chatId = 5278783015;
var messages = [];

for (var i = 0; i < rows.length; i++) {
    var r = rows[i];
    var devId = r.device_id || (r.tags && r.tags.device_id) || r.name || 'edge-01';
    var lat = parseFloat(r.lat) || 0;
    var lon = parseFloat(r.lon) || 0;
    if (lat === 0 && lon === 0) continue;

    var isMuted = flow.get('muted_' + devId) || global.get('muted_' + devId) || false;
    if (isMuted) continue;

    var isInside = false;
    if (vertices && Array.isArray(vertices) && vertices.length >= 3) {
        var inside = false;
        for (var j = 0, k = vertices.length - 1; j < vertices.length; k = j++) {
            var xi = vertices[j].lat, yi = vertices[j].lon;
            var xj = vertices[k].lat, yj = vertices[k].lon;
            var intersect = ((yi > lon) !== (yj > lon)) &&
                (lat < (xj - xi) * (lon - yi) / (yj - yi) + xi);
            if (intersect) inside = !inside;
        }
        isInside = inside;
    } else {
        isInside = (lat >= fenceMinLat && lat <= fenceMaxLat &&
                    lon >= fenceMinLon && lon <= fenceMaxLon);
    }

    if (!isInside) {
        var now = Date.now();
        var lastAlertTime = flow.get('last_alert_time_' + devId) || 0;
        // Anti-flood de 40 segundos
        if ((now - lastAlertTime) < 40000) {
            continue;
        }
        flow.set('last_alert_time_' + devId, now);

        var dLat = (lat - centerLat) * Math.PI / 180;
        var dLon = (lon - centerLon) * Math.PI / 180;
        var a = Math.sin(dLat/2) * Math.sin(dLat/2) +
                Math.cos(centerLat * Math.PI / 180) * Math.cos(lat * Math.PI / 180) *
                Math.sin(dLon/2) * Math.sin(dLon/2);
        var dist = R * 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1-a));

        var distToBorderLat = 0;
        if (lat < fenceMinLat) distToBorderLat = fenceMinLat - lat;
        else if (lat > fenceMaxLat) distToBorderLat = lat - fenceMaxLat;

        var distToBorderLon = 0;
        if (lon < fenceMinLon) distToBorderLon = fenceMinLon - lon;
        else if (lon > fenceMaxLon) distToBorderLon = lon - fenceMaxLon;

        var dLatBorder = distToBorderLat * Math.PI / 180;
        var dLonBorder = distToBorderLon * Math.PI / 180;
        var aBorder = Math.sin(dLatBorder/2) * Math.sin(dLatBorder/2) +
                     Math.cos(lat * Math.PI / 180) * Math.cos(lat * Math.PI / 180) *
                     Math.sin(dLonBorder/2) * Math.sin(dLonBorder/2);
        var distBorder = R * 2 * Math.atan2(Math.sqrt(aBorder), Math.sqrt(1-aBorder));

        var mapsUrl = 'https://www.google.com/maps?q=' + lat + ',' + lon;

        var text = '🔴 *ALERTA AUTOMÁTICA DE GEOFENCE*\n\n';
        text += '📛 Módulo: `' + devId + '`\n';
        text += '⚠️ Estado: *FUERA DEL PERÍMETRO (InfluxDB)*\n\n';
        text += '📍 Última Ubicación registrada:\n';
        text += '[Ver en Google Maps](' + mapsUrl + ')\n\n';
        text += '📏 Distancia al borde del fence: *' + distBorder.toFixed(1) + ' metros*\n';
        text += '📏 Distancia al centro del fence: *' + dist.toFixed(1) + ' metros*\n\n';
        text += '🔋 Batería: ' + (r.battery !== undefined ? r.battery : 'N/A') + '%\n';
        text += '📶 RSSI: ' + (r.rssi !== undefined ? r.rssi : 'N/A') + ' dBm | SNR: ' + (r.snr !== undefined ? r.snr : 'N/A') + '\n';
        text += '⏱️ Ciclo: #' + (r.wake_count || 0);

        messages.push({
            payload: {
                chatId: chatId,
                type: 'message',
                content: text,
                options: { parse_mode: 'Markdown', disable_web_page_preview: false }
            }
        });
    }
}

if (messages.length === 0) return null;
if (messages.length === 1) return messages[0];
return [messages];

// Guardar el chatId original para la respuesta
flow.set('tg_modulos_chatId', msg.originalMessage.chat.id);

// Query para obtener el último registro de cada device_id activo en las últimas 24h
msg.query = 'SELECT last("latitude") AS lat, last("longitude") AS lon FROM "cattle_position" WHERE time > now() - 24h GROUP BY "device_id"';
return msg;

var results = msg.payload;
var chatId = flow.get('tg_modulos_chatId');

if (!results || results.length === 0) {
    msg.payload = {
        chatId: chatId,
        type: 'message',
        content: '📡 No hay módulos activos en las últimas 24 horas.',
        options: { parse_mode: 'Markdown' }
    };
    return msg;
}

// Extraer device_ids únicos
var devices = [];
var groupResults = msg.payload;

// InfluxDB GROUP BY devuelve un array de series, cada una con tags
if (Array.isArray(groupResults)) {
    for (var i = 0; i < groupResults.length; i++) {
        var row = groupResults[i];
        var devId = '';
        // El device_id puede venir como tag en el objeto o en groupTags
        if (row.device_id) devId = row.device_id;
        else if (row.tags && row.tags.device_id) devId = row.tags.device_id;
        else if (row.name) devId = row.name;
        if (devId && devices.indexOf(devId) === -1) {
            devices.push(devId);
        }
    }
}

if (devices.length === 0) {
    msg.payload = {
        chatId: chatId,
        type: 'message',
        content: '📡 No se encontraron módulos activos.',
        options: { parse_mode: 'Markdown' }
    };
    return msg;
}

// Construir botones inline (un botón por módulo)
var keyboard = [];
for (var j = 0; j < devices.length; j++) {
    keyboard.push([{ text: '📍 ' + devices[j], callback_data: '/detalle_' + devices[j] }]);
}

var text = '📡 *Módulos Activos (' + devices.length + '):*\n\n';
text += 'Seleccioná un módulo para ver su ubicación y estado:';

msg.payload = {
    chatId: chatId,
    type: 'message',
    content: text,
    options: {
        parse_mode: 'Markdown',
        reply_markup: JSON.stringify({ inline_keyboard: keyboard })
    }
};
return msg;

var callbackData = msg.payload.content || '';
var chatId = msg.payload.chatId;

if (callbackData.startsWith('/toggle_mute_')) {
    var deviceId = callbackData.replace('/toggle_mute_', '');
    var current = flow.get('muted_' + deviceId) || global.get('muted_' + deviceId) || false;
    var newState = !current;
    flow.set('muted_' + deviceId, newState);
    global.set('muted_' + deviceId, newState);

    var text = newState ? 
        '🔕 *Alertas silenciadas* para el módulo `' + deviceId + '`.\nNo recibirás notificaciones automáticas si sale del perímetro.' :
        '🔔 *Alertas activadas* para el módulo `' + deviceId + '`.\nRecibirás notificaciones si sale del perímetro.';

    var keyboard = [
        [{ text: newState ? '🔔 Activar Alertas' : '🔕 Silenciar Alertas', callback_data: '/toggle_mute_' + deviceId }],
        [{ text: '📍 Ver Detalle de ' + deviceId, callback_data: '/detalle_' + deviceId }]
    ];

    return [null, {
        payload: {
            chatId: chatId,
            type: 'message',
            content: text,
            options: {
                parse_mode: 'Markdown',
                reply_markup: JSON.stringify({ inline_keyboard: keyboard })
            }
        }
    }];
}

// Extraer device_id del callback_data: '/detalle_edge-01' → 'edge-01'
if (!callbackData.startsWith('/detalle_')) {
    return null;
}
var deviceId = callbackData.replace('/detalle_', '');

// Guardar contexto para la respuesta
flow.set('tg_detalle_chatId', chatId);
flow.set('tg_detalle_deviceId', deviceId);

// Query con filtro por device_id
msg.query = 'SELECT last("latitude") AS lat, last("longitude") AS lon, last("battery") AS battery, last("rssi") AS rssi, last("snr") AS snr, last("wake_count") AS wake_count FROM "cattle_position" WHERE "device_id" = \'' + deviceId + '\' AND time > now() - 24h';
return [msg, null];

var results = msg.payload;
var chatId = flow.get('tg_detalle_chatId');
var deviceId = flow.get('tg_detalle_deviceId');

if (!results || results.length === 0) {
    msg.payload = {
        chatId: chatId,
        type: 'message',
        content: '❌ No se encontraron datos para el módulo `' + deviceId + '`.',
        options: { parse_mode: 'Markdown' }
    };
    return msg;
}

var r = results[0];
var lat = r.lat || 0;
var lon = r.lon || 0;

// Evaluar geofence (bounding box)
var fenceMinLat = flow.get('fence_min_lat') || global.get('fence_min_lat') || -34.9250;
var fenceMaxLat = flow.get('fence_max_lat') || global.get('fence_max_lat') || -34.9150;
var fenceMinLon = flow.get('fence_min_lon') || global.get('fence_min_lon') || -57.9600;
var fenceMaxLon = flow.get('fence_max_lon') || global.get('fence_max_lon') || -57.9450;

var isInside = (lat >= fenceMinLat && lat <= fenceMaxLat &&
               lon >= fenceMinLon && lon <= fenceMaxLon);

var statusIcon = isInside ? '🟢' : '🔴';
var statusText = isInside ? 'DENTRO del perímetro' : 'FUERA del perímetro';
var isMuted = flow.get('muted_' + deviceId) || global.get('muted_' + deviceId) || false;
var muteText = isMuted ? '🔕 Alertas: *SILENCIADAS*' : '🔔 Alertas: *ACTIVAS*';

var mapsUrl = 'https://www.google.com/maps?q=' + lat + ',' + lon;

var text = '🐄 *Detalle del Módulo:* `' + deviceId + '`\n\n';
text += statusIcon + ' Estado: *' + statusText + '*\n';
text += muteText + '\n\n';
text += '📍 Ubicación:\n';
text += '[🗺️ Ver en Google Maps](' + mapsUrl + ')\n\n';
text += '🔋 Batería: ' + (r.battery || 'N/A') + '%\n';
text += '📶 RSSI: ' + (r.rssi || 'N/A') + ' dBm\n';
text += '📶 SNR: ' + (r.snr || 'N/A') + '\n';
text += '⏱️ Último ciclo: #' + (r.wake_count || 'N/A');

var keyboard = [
    [{ text: isMuted ? '🔔 Activar Alertas' : '🔕 Silenciar Alertas', callback_data: '/toggle_mute_' + deviceId }]
];

msg.payload = {
    chatId: chatId,
    type: 'message',
    content: text,
    options: { parse_mode: 'Markdown', disable_web_page_preview: false, reply_markup: JSON.stringify({ inline_keyboard: keyboard }) }
};
return msg;

var data = (typeof msg.payload === 'string') ? JSON.parse(msg.payload) : (msg.payload || {});
if (data.min_lat !== undefined) { flow.set('fence_min_lat', data.min_lat); global.set('fence_min_lat', data.min_lat); }
if (data.max_lat !== undefined) { flow.set('fence_max_lat', data.max_lat); global.set('fence_max_lat', data.max_lat); }
if (data.min_lon !== undefined) { flow.set('fence_min_lon', data.min_lon); global.set('fence_min_lon', data.min_lon); }
if (data.max_lon !== undefined) { flow.set('fence_max_lon', data.max_lon); global.set('fence_max_lon', data.max_lon); }
if (data.vertices !== undefined || data.vertices_json !== undefined) {
    var vJson = data.vertices_json || (typeof data.vertices === 'string' ? data.vertices : JSON.stringify(data.vertices));
    flow.set('fence_vertices_json', vJson); global.set('fence_vertices_json', vJson);
}
node.status({fill:'green', shape:'dot', text:'Fence actualizado'});
return null;

var chatId = msg.originalMessage ? msg.originalMessage.chat.id : (msg.payload ? msg.payload.chatId : flow.get('tg_alertas_chatId'));
var rawText = (msg.originalMessage && msg.originalMessage.text) ? msg.originalMessage.text : (msg.payload && typeof msg.payload.content === 'string' ? msg.payload.content : '');
var arg = rawText.replace(/^\/(silenciar|alertas)(?:@[^\s]+)?\s*/i, '').trim();

if (arg !== '') {
    var parts = arg.split(/\s+/);
    var devId = parts[0];
    var action = parts[1] ? parts[1].toLowerCase() : null;

    var current = flow.get('muted_' + devId) || global.get('muted_' + devId) || false;
    var newState = !current;
    if (action === 'on' || action === 'mute' || action === 'silenciar') newState = true;
    else if (action === 'off' || action === 'unmute' || action === 'activar') newState = false;

    flow.set('muted_' + devId, newState);
    global.set('muted_' + devId, newState);

    var text = newState ? 
        '🔕 *Alertas silenciadas* para el módulo `' + devId + '`.\nNo recibirás notificaciones automáticas si sale del perímetro.' :
        '🔔 *Alertas activadas* para el módulo `' + devId + '`.\nRecibirás notificaciones si sale del perímetro.';

    var keyboard = [
        [{ text: newState ? '🔔 Activar Alertas' : '🔕 Silenciar Alertas', callback_data: '/toggle_mute_' + devId }],
        [{ text: '📍 Ver Detalle de ' + devId, callback_data: '/detalle_' + devId }]
    ];

    msg.payload = {
        chatId: chatId,
        type: 'message',
        content: text,
        options: {
            parse_mode: 'Markdown',
            reply_markup: JSON.stringify({ inline_keyboard: keyboard })
        }
    };
    return [null, msg];
}

flow.set('tg_alertas_chatId', chatId);
msg.query = 'SELECT last("latitude") AS lat FROM "cattle_position" WHERE time > now() - 24h GROUP BY "device_id"';
return [msg, null];

var results = msg.payload;
var chatId = flow.get('tg_alertas_chatId');
var devices = [];

if (Array.isArray(results)) {
    for (var i = 0; i < results.length; i++) {
        var row = results[i];
        var devId = '';
        if (row.device_id) devId = row.device_id;
        else if (row.tags && row.tags.device_id) devId = row.tags.device_id;
        else if (row.name) devId = row.name;
        if (devId && devices.indexOf(devId) === -1) {
            devices.push(devId);
        }
    }
}
if (devices.indexOf('edge-01') === -1) {
    devices.push('edge-01');
}

var keyboard = [];
for (var j = 0; j < devices.length; j++) {
    var d = devices[j];
    var isMuted = flow.get('muted_' + d) || global.get('muted_' + d) || false;
    var btnText = isMuted ? '🔕 ' + d + ' (SILENCIADO) ➔ 🔔 Activar' : '🔔 ' + d + ' (ACTIVO) ➔ 🔕 Silenciar';
    keyboard.push([{ text: btnText, callback_data: '/toggle_mute_' + d }]);
}

var text = '🔔 *Gestión de Alertas por Módulo*\n\n';
text += 'Seleccioná un módulo para silenciar 🔕 o activar 🔔 sus notificaciones de salida del perímetro:\n\n';
text += '💡 _Comando rápido:_ `/silenciar <modulo>`';

msg.payload = {
    chatId: chatId,
    type: 'message',
    content: text,
    options: {
        parse_mode: 'Markdown',
        reply_markup: JSON.stringify({ inline_keyboard: keyboard })
    }
};
return msg;

var lat = flow.get('sim_lat') || -34.9205;
var lon = flow.get('sim_lon') || -57.9536;
if (msg.topic === 'lat') { flow.set('sim_lat', parseFloat(msg.payload)); return null; }
if (msg.topic === 'lon') { flow.set('sim_lon', parseFloat(msg.payload)); return null; }
lat = flow.get('sim_lat') || -34.9205;
lon = flow.get('sim_lon') || -57.9536;
msg.payload = JSON.stringify({ lat: lat, lon: lon, timestamp: new Date().toISOString() });
msg.retain = true;
node.status({fill:'green', shape:'dot', text: lat.toFixed(4) + ', ' + lon.toFixed(4)});
return msg;

var min_lat = flow.get('fence_min_lat') || -34.9250;
var max_lat = flow.get('fence_max_lat') || -34.9150;
var min_lon = flow.get('fence_min_lon') || -57.9600;
var max_lon = flow.get('fence_max_lon') || -57.9450;
if (msg.topic === 'min_lat') { flow.set('fence_min_lat', parseFloat(msg.payload)); return null; }
if (msg.topic === 'max_lat') { flow.set('fence_max_lat', parseFloat(msg.payload)); return null; }
if (msg.topic === 'min_lon') { flow.set('fence_min_lon', parseFloat(msg.payload)); return null; }
if (msg.topic === 'max_lon') { flow.set('fence_max_lon', parseFloat(msg.payload)); return null; }
min_lat = flow.get('fence_min_lat') || -34.9250;
max_lat = flow.get('fence_max_lat') || -34.9150;
min_lon = flow.get('fence_min_lon') || -57.9600;
max_lon = flow.get('fence_max_lon') || -57.9450;
msg.payload = JSON.stringify({ min_lat: min_lat, max_lat: max_lat, min_lon: min_lon, max_lon: max_lon, timestamp: new Date().toISOString() });
msg.retain = true;
node.status({fill:'blue', shape:'dot', text:'Fence actualizado'});
return msg;

var body = (typeof msg.payload === 'string') ? JSON.parse(msg.payload) : (msg.payload || {});
var vertices = body.vertices || [];
if (!Array.isArray(vertices) || vertices.length < 3) {
    msg.payload = { status: 'error', message: 'Polígono inválido: mínimo 3 vértices requeridos.' };
    msg.statusCode = 400;
    return [null, null, msg];
}
var min_lat = vertices[0].lat, max_lat = vertices[0].lat;
var min_lon = vertices[0].lon, max_lon = vertices[0].lon;
for (var i = 1; i < vertices.length; i++) {
    if (vertices[i].lat < min_lat) min_lat = vertices[i].lat;
    if (vertices[i].lat > max_lat) max_lat = vertices[i].lat;
    if (vertices[i].lon < min_lon) min_lon = vertices[i].lon;
    if (vertices[i].lon > max_lon) max_lon = vertices[i].lon;
}
min_lat = Number(min_lat.toFixed(6));
max_lat = Number(max_lat.toFixed(6));
min_lon = Number(min_lon.toFixed(6));
max_lon = Number(max_lon.toFixed(6));

flow.set('fence_min_lat', min_lat); global.set('fence_min_lat', min_lat);
flow.set('fence_max_lat', max_lat); global.set('fence_max_lat', max_lat);
flow.set('fence_min_lon', min_lon); global.set('fence_min_lon', min_lon);
flow.set('fence_max_lon', max_lon); global.set('fence_max_lon', max_lon);
flow.set('fence_vertices_json', JSON.stringify(vertices)); global.set('fence_vertices_json', JSON.stringify(vertices));

var esp32Payload = { min_lat: min_lat, max_lat: max_lat, min_lon: min_lon, max_lon: max_lon };
var mqttMsg = { topic: 'geofence/config_update', payload: JSON.stringify(esp32Payload), qos: 1, retain: true };

var fields = { min_lat: min_lat, max_lat: max_lat, min_lon: min_lon, max_lon: max_lon, vertices_json: JSON.stringify(vertices), vertex_count: vertices.length };
var tags = { config_id: 'active' };
var influxMsg = { payload: [fields, tags] };

msg.statusCode = 200;
msg.payload = { status: 'success', message: 'Geofence (' + vertices.length + ' vértices) guardado en InfluxDB y MQTT.', topic: 'geofence/config_update', timestamp: Math.floor(Date.now() / 1000) };
return [mqttMsg, influxMsg, msg];

msg.statusCode = 200;
if (Array.isArray(msg.payload) && msg.payload.length > 0 && msg.payload[0].vertices_json) {
    var row = msg.payload[0];
    var vertices = [];
    try { vertices = JSON.parse(row.vertices_json); } catch(e) {}
    msg.payload = {
        status: 'success',
        fence: {
            vertices: vertices,
            min_lat: row.min_lat,
            max_lat: row.max_lat,
            min_lon: row.min_lon,
            max_lon: row.max_lon
        }
    };
} else {
    var vJson = global.get('fence_vertices_json') || flow.get('fence_vertices_json');
    if (vJson) {
        var vertices = [];
        try { vertices = JSON.parse(vJson); } catch(e){}
        msg.payload = {
            status: 'success',
            fence: {
                vertices: vertices,
                min_lat: global.get('fence_min_lat'),
                max_lat: global.get('fence_max_lat'),
                min_lon: global.get('fence_min_lon'),
                max_lon: global.get('fence_max_lon')
            }
        };
    } else {
        msg.payload = { status: 'error', message: 'No geofence configured yet in database' };
        msg.statusCode = 404;
    }
}
return msg;

if (Array.isArray(msg.payload) && msg.payload.length > 0) {
    var row = msg.payload[0];
    if (row.min_lat !== undefined) { flow.set('fence_min_lat', row.min_lat); global.set('fence_min_lat', row.min_lat); }
    if (row.max_lat !== undefined) { flow.set('fence_max_lat', row.max_lat); global.set('fence_max_lat', row.max_lat); }
    if (row.min_lon !== undefined) { flow.set('fence_min_lon', row.min_lon); global.set('fence_min_lon', row.min_lon); }
    if (row.max_lon !== undefined) { flow.set('fence_max_lon', row.max_lon); global.set('fence_max_lon', row.max_lon); }
    if (row.vertices_json !== undefined) { flow.set('fence_vertices_json', row.vertices_json); global.set('fence_vertices_json', row.vertices_json); }
    node.status({fill:'green', shape:'dot', text:'Geofence cargado de DB: ' + row.min_lat + ',' + row.min_lon});
} else {
    node.status({fill:'yellow', shape:'ring', text:'Sin geofence en DB'});
}
return null;
